class Solution:
    def containsPattern(self, arr, m, k):
        n = len(arr)
        for i in range(n - m * k + 1):
            pattern = arr[i:i + m]
            ok = True
            for rep in range(1, k):
                start = i + rep * m
                if arr[start:start + m] != pattern:
                    ok = False
                    break
            if ok:
                return True
        return False

