class Solution:
    def containsPattern(self, arr, m, k):
        n = len(arr)
        if m * k > n:
            return False
        count = 0
        threshold = m * (k - 1)
        for i in range(n - m):
            if arr[i] == arr[i + m]:
                count += 1
                if count >= threshold:
                    return True
            else:
                count = 0
        return False

