var containsPattern = function(arr, m, k) {
    const n = arr.length;
    if (m * k > n) return false;
    let count = 0;
    const threshold = m * (k - 1);
    for (let i = 0; i < n - m; i++) {
        if (arr[i] === arr[i + m]) {
            count++;
            if (count >= threshold) return true;
        } else {
            count = 0;
        }
    }
    return false;
};
